import statuses from"statuses";function toObject(t){const s={};for(const e of t)s[e[0]]=e[1].trim();return s}function toQueryString(t){const s=new URLSearchParams(t);return s.toString()}function reject(t){const s={status:t.status,statusText:t.statusText||statuses[t.status]};return t.body&&(s.body=t.body),t.message&&(s.message=t.message),Promise.reject(s)}export{toObject,toQueryString,reject};